+    assert_eq!(format!("{:?}", submit), "ShadowOnly");
+
+    let decision = governor.complete_shadow_evaluation(
+        "prop-perf-1",
+        &baseline(),
+        &RuntimeMetrics {
+            latency_ms: 94,
+            throughput_rps: 1130,
+            error_rate_pct: 0.7,
+            memory_mb: 350,
+        },
+        false,
+    );
