+    let result = ledger.verify_proof(&att, &policy, 1_000_001, "trace-rev".to_string());
+    assert!(!result.is_verified());
+    match &result {
+        ZkVerificationResult::Rejected { error_code, .. } => {
+            assert_eq!(error_code, error_codes::ERR_ZKA_REVOKED);
+        }
